     8→#[test]
     9→fn jjtg_pace_state_serialization() {
    10→    let state = jjrg_PaceState::Rough;
    11→    let json = serde_json::to_string(&state).unwrap();
    12→    assert_eq!(json, "\"rough\"");
    13→}
    14→
    15→// Helper to create a minimal valid Gallops structure
    16→fn make_valid_gallops() -> jjrg_Gallops {
    17→    jjrg_Gallops {
    18→        next_heat_seed: "AB".to_string(),
    19→        heats: BTreeMap::new(),
    20→    }
    21→}
    22→
    23→// Helper to create a valid Tack (uses JJRG_UNKNOWN_COMMIT for consistent commit format)
    24→fn make_valid_tack(state: jjrg_PaceState, silks: &str, direction: Option<String>) -> jjrg_Tack {
    25→    jjrg_Tack {
    26→        ts: "260101-1200".to_string(),
    27→        state,
    28→        text: "Test tack text".to_string(),
    29→        silks: silks.to_string(),
    30→        commit: JJRG_UNKNOWN_COMMIT.to_string(),
    31→        direction,
    32→    }
    33→}
    34→
    35→// Helper to create a valid Pace
    36→fn make_valid_pace(heat_id: &str, silks: &str) -> (String, jjrg_Pace) {
    37→    let pace_key = format!("₢{}AAA", heat_id);
    38→    let pace = jjrg_Pace {
    39→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, silks, None)],
    40→    };
    41→    (pace_key, pace)
    42→}
    43→
    44→// Helper to create a valid Heat
    45→fn make_valid_heat(heat_id: &str, silks: &str) -> (String, jjrg_Heat) {
    46→    let heat_key = format!("₣{}", heat_id);
    47→    let (pace_key, pace) = make_valid_pace(heat_id, "test-pace");
    48→    let mut paces = BTreeMap::new();
    49→    paces.insert(pace_key.clone(), pace);
    50→
    51→    let heat = jjrg_Heat {
    52→        silks: silks.to_string(),
    53→        creation_time: "260101".to_string(),
    54→        status: jjrg_HeatStatus::Racing,
    55→        order: vec![pace_key],
    56→        next_pace_seed: "AAB".to_string(),
    57→        paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
    58→        paces,
    59→    };
    60→    (heat_key, heat)
    61→}
