   388→    assert_eq!(zjjrg_increment_seed("Az"), "A0");
   389→}
   390→
   391→#[test]
   392→fn jjtg_zjjrg_increment_seed_carry() {
   393→    // '_' is position 63, should wrap to 'A' (position 0) and carry
   394→    assert_eq!(zjjrg_increment_seed("A_"), "BA");
   395→    assert_eq!(zjjrg_increment_seed("__"), "AA"); // Full wrap around
   396→}
   397→
   398→#[test]
   399→fn jjtg_zjjrg_increment_seed_three_chars() {
