   799→    heat.paces.get_mut(&pace1_key).unwrap().tacks[0].state = jjrg_PaceState::Complete;
   800→
   801→    // Add pace2 (complete) and pace3 (rough) and pace4 (rough)
   802→    let pace2_key = "₢ABAAB".to_string();
   803→    let pace3_key = "₢ABAAC".to_string();
   804→    let pace4_key = "₢ABAAD".to_string();
