   806→        tacks: vec![make_valid_tack(jjrg_PaceState::Complete, "second-pace", None)],
   807→    });
   808→    heat.paces.insert(pace3_key.clone(), jjrg_Pace {
   809→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "third-pace", None)],
   810→    });
   811→    heat.paces.insert(pace4_key.clone(), jjrg_Pace {
   812→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "fourth-pace", None)],
   813→    });
   814→    heat.order.push(pace2_key.clone());
   815→    heat.order.push(pace3_key.clone());
   816→    heat.order.push(pace4_key.clone());
   817→    heat.next_pace_seed = "AAE".to_string();
