   819→    // Order: [complete1, complete2, rough3, rough4]
   820→    gallops.heats.insert(heat_key.clone(), heat);
   821→
   822→    // Move fourth pace (rough) to first actionable position
   823→    // Should go BEFORE pace3 (first rough), not before pace1 (absolute first)
   824→    let args = jjrg_RailArgs {
   825→        firemark: "AB".to_string(),
