   836→
   837→    // Expected order: [complete1, complete2, rough4, rough3]
   838→    let heat = gallops.heats.get(&heat_key).unwrap();
   839→    assert_eq!(heat.order[0], pace1_key, "complete1 should stay at index 0");
   840→    assert_eq!(heat.order[1], pace2_key, "complete2 should stay at index 1");
