    85→// Validation helper functions
    86→
    87→/// Check if string contains only URL-safe base64 characters
    88→pub(crate) fn zjjrg_is_base64(s: &str) -> bool {
    89→    s.bytes().all(|b| JJRF_CHARSET.contains(&b))
    90→}
    91→
    92→/// Check if string is valid kebab-case (non-empty, lowercase alphanumeric with hyphens)
    93→pub(crate) fn zjjrg_is_kebab_case(s: &str) -> bool {
    94→    if s.is_empty() {
    95→        return false;
    96→    }
    97→    // Pattern: [a-z0-9]+(-[a-z0-9]+)*
    98→    let parts: Vec<&str> = s.split('-').collect();
    99→    for part in parts {
   100→        if part.is_empty() {
   101→            return false;
   102→        }
   103→        if !part.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit()) {
   104→            return false;
   105→        }
   106→    }
   107→    true
   108→}
   109→
   110→/// Check if string matches YYMMDD format
   111→pub(crate) fn zjjrg_is_yymmdd(s: &str) -> bool {
   112→    if s.len() != 6 {
   113→        return false;
   114→    }
   115→    s.chars().all(|c| c.is_ascii_digit())
   116→}
   117→
   118→/// Check if string matches YYMMDD-HHMM format
   119→pub(crate) fn zjjrg_is_yymmdd_hhmm(s: &str) -> bool {
   120→    if s.len() != 11 {
   121→        return false;
   122→    }
   123→    let parts: Vec<&str> = s.split('-').collect();
   124→    if parts.len() != 2 {
   125→        return false;
   126→    }
   127→    parts[0].len() == 6
   128→        && parts[0].chars().all(|c| c.is_ascii_digit())
   129→        && parts[1].len() == 4
   130→        && parts[1].chars().all(|c| c.is_ascii_digit())
   131→}
   132→
   133→/// Check if string is valid commit SHA format
   134→///
   135→/// Length is derived from JJRG_UNKNOWN_COMMIT constant.
   136→pub(crate) fn zjjrg_is_commit_sha(s: &str) -> bool {
   137→    s.len() == JJRG_UNKNOWN_COMMIT.len() && s.chars().all(|c| c.is_ascii_hexdigit())
   138→}
