   140→impl jjrg_Gallops {
   141→    /// Load Gallops from a file path
   142→    pub fn jjrg_load(path: &Path) -> Result<Self, String> {
   143→        let content = fs::read_to_string(path)
   144→            .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
   145→
   146→        let gallops: jjrg_Gallops = serde_json::from_str(&content)
   147→            .map_err(|e| format!("Failed to parse JSON: {}", e))?;
   148→
   149→        Ok(gallops)
   150→    }
   151→
   152→    /// Save Gallops to a file path (atomic write)
   153→    pub fn jjrg_save(&self, path: &Path) -> Result<(), String> {
   154→        // Serialize to pretty JSON
   155→        let content = serde_json::to_string_pretty(self)
   156→            .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
   157→
   158→        // Create temp file in same directory for atomic rename
   159→        let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
   160→        let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
   161→
   162→        // Write to temp file
   163→        let mut file = fs::File::create(&temp_path)
   164→            .map_err(|e| format!("Failed to create temp file: {}", e))?;
   165→        file.write_all(content.as_bytes())
   166→            .map_err(|e| format!("Failed to write temp file: {}", e))?;
   167→        file.sync_all()
   168→            .map_err(|e| format!("Failed to sync temp file: {}", e))?;
   169→        drop(file);
   170→
   171→        // Atomic rename
   172→        fs::rename(&temp_path, path)
   173→            .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
   174→
   175→        Ok(())
   176→    }
   177→
   178→    /// Validate the Gallops structure
   179→    ///
   180→    /// Returns Ok(()) if valid, Err(Vec<String>) with all validation errors otherwise.
   181→    pub fn jjrg_validate(&self) -> Result<(), Vec<String>> {
   182→        let mut errors = Vec::new();
   183→
   184→        // Rule 1: next_heat_seed must be 2 URL-safe base64 characters
   185→        if self.next_heat_seed.len() != 2 {
   186→            errors.push(format!(
   187→                "next_heat_seed must be 2 characters, got {}",
   188→                self.next_heat_seed.len()
   189→            ));
   190→        } else if !zjjrg_is_base64(&self.next_heat_seed) {
   191→            errors.push(format!(
   192→                "next_heat_seed contains invalid base64 characters: '{}'",
   193→                self.next_heat_seed
   194→            ));
   195→        }
   196→
   197→        // Rule 2: heats object exists (implicitly satisfied by struct)
   198→
   199→        // Validate each Heat
   200→        for (heat_key, heat) in &self.heats {
   201→            self.zjjrg_validate_heat(heat_key, heat, &mut errors);
   202→        }
   203→
   204→        if errors.is_empty() {
   205→            Ok(())
   206→        } else {
   207→            Err(errors)
   208→        }
   209→    }
   210→
   211→    fn zjjrg_validate_heat(&self, heat_key: &str, heat: &jjrg_Heat, errors: &mut Vec<String>) {
   212→        let heat_ctx = format!("Heat '{}'", heat_key);
   213→
   214→        // Rule 3: Heat key must match ₣[A-Za-z0-9_-]{2}
   215→        if !heat_key.starts_with('₣') {
   216→            errors.push(format!("{}: key must start with '₣'", heat_ctx));
   217→        } else {
   218→            let suffix = &heat_key[3..]; // ₣ is 3 bytes in UTF-8
   219→            if suffix.len() != 2 {
   220→                errors.push(format!(
   221→                    "{}: key must have 2 base64 chars after '₣', got {}",
   222→                    heat_ctx,
   223→                    suffix.len()
   224→                ));
   225→            } else if !zjjrg_is_base64(suffix) {
   226→                errors.push(format!(
   227→                    "{}: key contains invalid base64 characters",
   228→                    heat_ctx
   229→                ));
   230→            }
   231→        }
   232→
   233→        // Rule 4: Required Heat fields
   234→        // silks (non-empty kebab-case)
   235→        if !zjjrg_is_kebab_case(&heat.silks) {
   236→            errors.push(format!(
   237→                "{}: silks must be non-empty kebab-case, got '{}'",
   238→                heat_ctx, heat.silks
   239→            ));
   240→        }
   241→
   242→        // creation_time (YYMMDD)
   243→        if !zjjrg_is_yymmdd(&heat.creation_time) {
   244→            errors.push(format!(
   245→                "{}: creation_time must be YYMMDD format, got '{}'",
   246→                heat_ctx, heat.creation_time
   247→            ));
   248→        }
   249→
   250→        // status (validated by serde enum)
   251→
   252→        // next_pace_seed (3 URL-safe base64 characters)
   253→        if heat.next_pace_seed.len() != 3 {
   254→            errors.push(format!(
   255→                "{}: next_pace_seed must be 3 characters, got {}",
   256→                heat_ctx,
   257→                heat.next_pace_seed.len()
   258→            ));
   259→        } else if !zjjrg_is_base64(&heat.next_pace_seed) {
   260→            errors.push(format!(
   261→                "{}: next_pace_seed contains invalid base64 characters",
   262→                heat_ctx
   263→            ));
   264→        }
   265→
   266→        // Extract heat identity (base64 part without prefix) for pace validation
   267→        let heat_identity = if heat_key.starts_with('₣') && heat_key.len() >= 5 {
   268→            Some(&heat_key[3..]) // ₣ is 3 bytes
   269→        } else {
   270→            None
   271→        };
   272→
   273→        // Rule 5: order array and paces object must have identical key sets
   274→        let order_set: HashSet<&String> = heat.order.iter().collect();
   275→        let _paces_set: HashSet<&String> = heat.paces.keys().collect();
   276→
   277→        if order_set.len() != heat.order.len() {
   278→            errors.push(format!("{}: order array contains duplicate entries", heat_ctx));
   279→        }
   280→
   281→        let in_order_not_paces: Vec<_> = heat
   282→            .order
   283→            .iter()
   284→            .filter(|k| !heat.paces.contains_key(*k))
   285→            .collect();
   286→        let in_paces_not_order: Vec<_> = heat
   287→            .paces
   288→            .keys()
   289→            .filter(|k| !order_set.contains(k))
   290→            .collect();
   291→
   292→        if !in_order_not_paces.is_empty() {
   293→            errors.push(format!(
   294→                "{}: order contains keys not in paces: {:?}",
   295→                heat_ctx, in_order_not_paces
   296→            ));
   297→        }
   298→        if !in_paces_not_order.is_empty() {
   299→            errors.push(format!(
   300→                "{}: paces contains keys not in order: {:?}",
   301→                heat_ctx, in_paces_not_order
   302→            ));
   303→        }
   304→
   305→        // Validate each Pace
   306→        for (pace_key, pace) in &heat.paces {
   307→            self.zjjrg_validate_pace(&heat_ctx, heat_identity, pace_key, pace, errors);
   308→        }
   309→    }
   310→
   311→    fn zjjrg_validate_pace(
   312→        &self,
   313→        heat_ctx: &str,
   314→        heat_identity: Option<&str>,
   315→        pace_key: &str,
   316→        pace: &jjrg_Pace,
   317→        errors: &mut Vec<String>,
   318→    ) {
   319→        let pace_ctx = format!("{} Pace '{}'", heat_ctx, pace_key);
   320→
   321→        // Rule 6: Pace key must match ₢[A-Za-z0-9_-]{5}
   322→        if !pace_key.starts_with('₢') {
   323→            errors.push(format!("{}: key must start with '₢'", pace_ctx));
   324→        } else {
   325→            let suffix = &pace_key[3..]; // ₢ is 3 bytes in UTF-8
   326→            if suffix.len() != 5 {
   327→                errors.push(format!(
   328→                    "{}: key must have 5 base64 chars after '₢', got {}",
   329→                    pace_ctx,
   330→                    suffix.len()
   331→                ));
   332→            } else {
   333→                if !zjjrg_is_base64(suffix) {
   334→                    errors.push(format!(
   335→                        "{}: key contains invalid base64 characters",
   336→                        pace_ctx
   337→                    ));
   338→                }
   339→                // Pace must embed parent Heat identity (first 2 chars)
   340→                if let Some(heat_id) = heat_identity {
   341→                    if !suffix.starts_with(heat_id) {
   342→                        errors.push(format!(
   343→                            "{}: key must embed parent heat identity '{}', got '{}'",
   344→                            pace_ctx,
   345→                            heat_id,
   346→                            &suffix[..2.min(suffix.len())]
   347→                        ));
   348→                    }
   349→                }
   350→            }
   351→        }
   352→
   353→        // Rule 7: tacks must be non-empty array
   354→        if pace.tacks.is_empty() {
   355→            errors.push(format!("{}: tacks array must not be empty", pace_ctx));
   356→        }
   357→
   358→        // Validate each Tack
   359→        for (i, tack) in pace.tacks.iter().enumerate() {
   360→            self.zjjrg_validate_tack(&pace_ctx, i, tack, errors);
   361→        }
   362→    }
   363→
   364→    fn zjjrg_validate_tack(&self, pace_ctx: &str, index: usize, tack: &jjrg_Tack, errors: &mut Vec<String>) {
   365→        let tack_ctx = format!("{} Tack[{}]", pace_ctx, index);
   366→
   367→        // Rule 8: ts must be YYMMDD-HHMM
   368→        if !zjjrg_is_yymmdd_hhmm(&tack.ts) {
   369→            errors.push(format!(
   370→                "{}: ts must be YYMMDD-HHMM format, got '{}'",
   371→                tack_ctx, tack.ts
   372→            ));
   373→        }
   374→
   375→        // Rule 8: text must be non-empty
   376→        if tack.text.is_empty() {
   377→            errors.push(format!("{}: text must not be empty", tack_ctx));
   378→        }
   379→
   380→        // Rule 8: silks must be non-empty kebab-case
   381→        if !zjjrg_is_kebab_case(&tack.silks) {
   382→            errors.push(format!(
   383→                "{}: silks must be non-empty kebab-case, got '{}'",
   384→                tack_ctx, tack.silks
   385→            ));
   386→        }
   387→
   388→        // Rule 8: commit must be valid format (7 hex chars)
   389→        if !zjjrg_is_commit_sha(&tack.commit) {
   390→            errors.push(format!(
   391→                "{}: commit must be 7 hex characters, got '{}'",
   392→                tack_ctx, tack.commit
   393→            ));
   394→        }
   395→
   396→        // Rule 9: direction presence depends on state
   397→        match tack.state {
   398→            jjrg_PaceState::Bridled => {
   399→                match &tack.direction {
   400→                    None => {
   401→                        errors.push(format!(
   402→                            "{}: direction is required when state is 'bridled'",
   403→                            tack_ctx
   404→                        ));
   405→                    }
   406→                    Some(d) if d.is_empty() => {
   407→                        errors.push(format!(
   408→                            "{}: direction must not be empty when state is 'bridled'",
   409→                            tack_ctx
   410→                        ));
   411→                    }
   412→                    _ => {}
   413→                }
   414→            }
   415→            _ => {
   416→                if tack.direction.is_some() {
   417→                    errors.push(format!(
   418→                        "{}: direction must be absent when state is not 'bridled'",
   419→                        tack_ctx
   420→                    ));
   421→                }
   422→            }
   423→        }
   424→    }
   425→}
