   427→// ===== Seed Increment Helpers =====
   428→
   429→/// Increment a base64 seed string (with carry)
   430→/// Works for both 2-char (heat) and 3-char (pace) seeds
   431→pub(crate) fn zjjrg_increment_seed(seed: &str) -> String {
   432→    let mut chars: Vec<u8> = seed.bytes().collect();
   433→    let mut carry = true;
   434→
   435→    // Process from right to left
   436→    for i in (0..chars.len()).rev() {
   437→        if !carry {
   438→            break;
   439→        }
   440→
   441→        // Find current position in charset
   442→        let pos = JJRF_CHARSET.iter().position(|&c| c == chars[i]).unwrap_or(0);
   443→
   444→        if pos == 63 {
   445→            // Wrap around
   446→            chars[i] = JJRF_CHARSET[0];
   447→            // carry remains true
   448→        } else {
   449→            chars[i] = JJRF_CHARSET[pos + 1];
   450→            carry = false;
   451→        }
   452→    }
   453→
   454→    String::from_utf8(chars).unwrap_or_else(|_| seed.to_string())
   455→}
   456→
   457→/// Capture current commit SHA
   458→///
   459→/// Runs `git rev-parse --short=N HEAD` where N is derived from JJRG_UNKNOWN_COMMIT length.
   460→/// Returns JJRG_UNKNOWN_COMMIT on error (e.g., not in a git repo).
   461→pub fn jjrg_capture_commit_sha() -> String {
   462→    use std::process::Command;
   463→
   464→    let short_arg = format!("--short={}", JJRG_UNKNOWN_COMMIT.len());
   465→    match Command::new("git")
   466→        .args(["rev-parse", &short_arg, "HEAD"])
   467→        .output()
   468→    {
   469→        Ok(output) if output.status.success() => {
   470→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   471→        }
   472→        _ => JJRG_UNKNOWN_COMMIT.to_string(),
   473→    }
   474→}
   475→
   476→/// Create a new Tack with current timestamp and commit SHA
   477→///
   478→/// Centralizes Tack creation to ensure consistent timestamp/commit capture.
   479→/// All code creating new Tacks should use this helper.
   480→pub fn jjrg_make_tack(
   481→    state: jjrg_PaceState,
   482→    text: String,
   483→    silks: String,
   484→    direction: Option<String>,
   485→) -> jjrg_Tack {
   486→    jjrg_Tack {
   487→        ts: timestamp_full(),
   488→        state,
   489→        text,
   490→        silks,
   491→        commit: jjrg_capture_commit_sha(),
   492→        direction,
   493→    }
   494→}
