   613→impl jjrg_Gallops {
   614→    /// Nominate a new Heat
   615→    ///
   616→    /// Creates a new Heat with empty Pace structure and creates the paddock file.
   617→    pub fn jjrg_nominate(&mut self, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
   618→        // Validate silks is kebab-case
   619→        if !zjjrg_is_kebab_case(&args.silks) {
   620→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   621→        }
   622→
   623→        // Validate created is YYMMDD
   624→        if !zjjrg_is_yymmdd(&args.created) {
   625→            return Err(format!("created must be YYMMDD format, got '{}'", args.created));
   626→        }
   627→
   628→        // Allocate Firemark from next_heat_seed
   629→        let firemark_str = format!("{}{}", FIREMARK_PREFIX, self.next_heat_seed);
   630→        let heat_id = self.next_heat_seed.clone();
   631→
   632→        // Compute paddock path
   633→        let paddock_file = format!(".claude/jjm/jjp_{}.md", heat_id);
   634→
   635→        // Create paddock file with template
   636→        let paddock_path = base_path.join(&paddock_file);
   637→        if let Some(parent) = paddock_path.parent() {
   638→            fs::create_dir_all(parent)
   639→                .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
   640→        }
   641→
   642→        let paddock_content = format!(
   643→            "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
   644→            args.silks
   645→        );
   646→
   647→        fs::write(&paddock_path, paddock_content)
   648→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   649→
   650→        // Create new Heat
   651→        let heat = jjrg_Heat {
   652→            silks: args.silks,
   653→            creation_time: args.created,
   654→            status: jjrg_HeatStatus::Racing,
   655→            order: Vec::new(),
   656→            next_pace_seed: "AAA".to_string(),
   657→            paddock_file,
   658→            paces: BTreeMap::new(),
   659→        };
   660→
   661→        // Insert Heat
   662→        self.heats.insert(firemark_str.clone(), heat);
   663→
   664→        // Increment next_heat_seed
   665→        self.next_heat_seed = zjjrg_increment_seed(&self.next_heat_seed);
   666→
   667→        Ok(jjrg_NominateResult { firemark: firemark_str })
   668→    }
   669→
   670→    /// Slate a new Pace
   671→    ///
   672→    /// Adds a new Pace to a Heat with an initial Tack in rough state.
   673→    /// Positioning: use before/after/first to insert at specific location.
   674→    pub fn jjrg_slate(&mut self, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
   675→        // Validate silks is kebab-case
   676→        if !zjjrg_is_kebab_case(&args.silks) {
   677→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   678→        }
   679→
   680→        // Validate text is non-empty
   681→        if args.text.is_empty() {
   682→            return Err("text must not be empty".to_string());
   683→        }
   684→
   685→        // Validate positioning mutual exclusivity
   686→        let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   687→            .iter()
   688→            .filter(|&&x| x)
   689→            .count();
   690→        if position_count > 1 {
   691→            return Err("Only one of --before, --after, or --first may be specified".to_string());
   692→        }
   693→
   694→        // Parse and normalize firemark
   695→        let firemark = Firemark::jjrf_parse(&args.firemark)
   696→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   697→        let firemark_key = firemark.jjrf_display();
   698→
   699→        // Verify Heat exists
   700→        let heat = self.heats.get_mut(&firemark_key)
   701→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   702→
   703→        // If --before or --after specified, validate target coronet exists
   704→        let insert_position = if let Some(ref before_str) = args.before {
   705→            let target = Coronet::jjrf_parse(before_str)
   706→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   707→            let target_key = target.jjrf_display();
   708→            let pos = heat.order.iter().position(|c| c == &target_key)
   709→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   710→            Some(pos) // Insert before this position
   711→        } else if let Some(ref after_str) = args.after {
   712→            let target = Coronet::jjrf_parse(after_str)
   713→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   714→            let target_key = target.jjrf_display();
   715→            let pos = heat.order.iter().position(|c| c == &target_key)
   716→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   717→            Some(pos + 1) // Insert after this position
   718→        } else if args.first {
   719→            Some(0) // Insert at beginning
   720→        } else {
   721→            None // Append to end (default)
   722→        };
   723→
   724→        // Construct Coronet
   725→        let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   726→
   727→        // Create initial Tack and Pace
   728→        let tack = jjrg_make_tack(
   729→            jjrg_PaceState::Rough,
   730→            args.text,
   731→            args.silks,
   732→            None,
   733→        );
   734→        let pace = jjrg_Pace {
   735→            tacks: vec![tack],
   736→        };
   737→
   738→        // Insert into order at determined position
   739→        match insert_position {
   740→            Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   741→            None => heat.order.push(coronet_str.clone()),
   742→        }
   743→        heat.paces.insert(coronet_str.clone(), pace);
   744→
   745→        // Increment next_pace_seed
   746→        heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   747→
   748→        Ok(jjrg_SlateResult { coronet: coronet_str })
   749→    }
   750→
   751→    /// Rail - reorder Paces within a Heat
   752→    ///
   753→    /// Supports two modes:
   754→    /// - Order mode: replace entire sequence with provided order array
   755→    /// - Move mode: relocate a single pace using positioning flags
   756→    pub fn jjrg_rail(&mut self, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   757→        // Parse and normalize firemark
   758→        let firemark = Firemark::jjrf_parse(&args.firemark)
   759→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   760→        let firemark_key = firemark.jjrf_display();
   761→
   762→        // Verify Heat exists
   763→        let heat = self.heats.get_mut(&firemark_key)
   764→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   765→
   766→        // Mode detection: if move_coronet present, use move mode
   767→        if let Some(ref move_str) = args.move_coronet {
   768→            // Move mode validation
   769→            if !args.order.is_empty() {
   770→                return Err("Cannot combine --move with positional coronets".to_string());
   771→            }
   772→
   773→            // Parse and normalize move coronet
   774→            let move_coronet = Coronet::jjrf_parse(move_str)
   775→                .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   776→            let move_key = move_coronet.jjrf_display();
   777→
   778→            // Validate move coronet exists in heat
   779→            if !heat.paces.contains_key(&move_key) {
   780→                return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   781→            }
   782→
   783→            // Count positioning flags
   784→            let position_count = [
   785→                args.before.is_some(),
   786→                args.after.is_some(),
   787→                args.first,
   788→                args.last,
   789→            ].iter().filter(|&&x| x).count();
   790→
   791→            if position_count == 0 {
   792→                return Err("Move mode requires exactly one positioning flag".to_string());
   793→            }
   794→            if position_count > 1 {
   795→                let mut flags = Vec::new();
   796→                if args.before.is_some() { flags.push("--before"); }
   797→                if args.after.is_some() { flags.push("--after"); }
   798→                if args.first { flags.push("--first"); }
   799→                if args.last { flags.push("--last"); }
   800→                return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   801→            }
   802→
   803→            // Determine target position and validate
   804→            let current_pos = heat.order.iter().position(|c| c == &move_key)
   805→                .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   806→
   807→            let new_pos = if args.first {
   808→                // Find first actionable pace (rough or bridled)
   809→                // If none found, use end of array (nothing actionable to precede)
   810→                let first_actionable_idx = heat.order.iter().position(|coronet| {
   811→                    if let Some(pace) = heat.paces.get(coronet) {
   812→                        if let Some(tack) = pace.tacks.first() {
   813→                            matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   814→                        } else {
   815→                            false
   816→                        }
   817→                    } else {
   818→                        false
   819→                    }
   820→                });
   821→                // Use len() as fallback so adjustment logic works correctly for "end" position
   822→                let target_idx = first_actionable_idx.unwrap_or(heat.order.len());
   823→                // If moving from before target, the target shifts down after removal
   824→                if current_pos < target_idx {
   825→                    target_idx - 1
   826→                } else {
   827→                    target_idx
   828→                }
   829→            } else if args.last {
   830→                heat.order.len() - 1
   831→            } else if let Some(ref before_str) = args.before {
   832→                let target = Coronet::jjrf_parse(before_str)
   833→                    .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   834→                let target_key = target.jjrf_display();
   835→
   836→                if target_key == move_key {
   837→                    return Err("Cannot position pace relative to itself".to_string());
   838→                }
   839→
   840→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   841→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   842→
   843→                // If moving from before target, the target shifts down after removal
   844→                if current_pos < target_pos {
   845→                    target_pos - 1
   846→                } else {
   847→                    target_pos
   848→                }
   849→            } else if let Some(ref after_str) = args.after {
   850→                let target = Coronet::jjrf_parse(after_str)
   851→                    .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   852→                let target_key = target.jjrf_display();
   853→
   854→                if target_key == move_key {
   855→                    return Err("Cannot position pace relative to itself".to_string());
   856→                }
   857→
   858→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   859→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   860→
   861→                // If moving from before target, the target shifts down after removal
   862→                if current_pos < target_pos {
   863→                    target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   864→                } else {
   865→                    target_pos + 1
   866→                }
   867→            } else {
   868→                unreachable!()
   869→            };
   870→
   871→            // Remove from current position and insert at new position
   872→            heat.order.remove(current_pos);
   873→            heat.order.insert(new_pos, move_key);
   874→
   875→        } else {
   876→            // Order mode: replace entire sequence
   877→
   878→            // Normalize the input order (add prefix if missing)
   879→            let normalized_order: Result<Vec<String>, String> = args.order.iter()
   880→                .map(|c| {
   881→                    let coronet = Coronet::jjrf_parse(c)
   882→                        .map_err(|e| format!("Invalid coronet '{}': {}", c, e))?;
   883→                    Ok(coronet.jjrf_display())
   884→                })
   885→                .collect();
   886→            let new_order = normalized_order?;
   887→
   888→            // Validate count matches
   889→            if new_order.len() != heat.order.len() {
   890→                return Err(format!(
   891→                    "Order count mismatch: got {}, expected {}",
   892→                    new_order.len(),
   893→                    heat.order.len()
   894→                ));
   895→            }
   896→
   897→            // Validate no duplicates
   898→            let new_set: HashSet<&String> = new_order.iter().collect();
   899→            if new_set.len() != new_order.len() {
   900→                return Err("Order contains duplicate Coronets".to_string());
   901→            }
   902→
   903→            // Validate all Coronets exist in paces
   904→            for coronet in &new_order {
   905→                if !heat.paces.contains_key(coronet) {
   906→                    return Err(format!("Coronet '{}' not found in Heat's paces", coronet));
   907→                }
   908→            }
   909→
   910→            // Validate all Coronets embed correct parent Firemark
   911→            for coronet in &new_order {
   912→                let c = Coronet::jjrf_parse(coronet).unwrap();
   913→                if c.jjrf_parent_firemark().jjrf_display() != firemark_key {
   914→                    return Err(format!(
   915→                        "Coronet '{}' does not embed parent Heat '{}'",
   916→                        coronet, firemark_key
   917→                    ));
   918→                }
   919→            }
   920→
   921→            // Replace order
   922→            heat.order = new_order;
   923→        }
   924→
   925→        // Return the new order
   926→        Ok(heat.order.clone())
   927→    }
   928→
   929→    /// Tally - add a new Tack to a Pace
   930→    ///
   931→    /// Prepends a new Tack with state transition and/or plan refinement.
   932→    pub fn jjrg_tally(&mut self, args: jjrg_TallyArgs) -> Result<(), String> {
   933→        // Parse and normalize coronet
   934→        let coronet = Coronet::jjrf_parse(&args.coronet)
   935→            .map_err(|e| format!("Invalid coronet: {}", e))?;
   936→        let coronet_key = coronet.jjrf_display();
   937→
   938→        // Extract parent Firemark
   939→        let firemark = coronet.jjrf_parent_firemark();
   940→        let firemark_key = firemark.jjrf_display();
   941→
   942→        // Verify Heat exists
   943→        let heat = self.heats.get_mut(&firemark_key)
   944→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   945→
   946→        // Verify Pace exists
   947→        let pace = heat.paces.get_mut(&coronet_key)
   948→            .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
   949→
   950→        // Read current Tack
   951→        let current_tack = pace.tacks.first()
   952→            .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
   953→
   954→        // Determine new state
   955→        let new_state = args.state.clone().unwrap_or_else(|| current_tack.state.clone());
   956→
   957→        // Determine new direction
   958→        let new_direction = match (&args.state, &new_state) {
   959→            // State explicitly set to bridled: direction required
   960→            (Some(jjrg_PaceState::Bridled), _) => {
   961→                match &args.direction {
   962→                    Some(d) if !d.is_empty() => Some(d.clone()),
   963→                    Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
   964→                    None => return Err("direction is required when state is bridled".to_string()),
   965→                }
   966→            }
   967→            // State explicitly set to something other than bridled: direction forbidden
   968→            (Some(_), _) => {
   969→                if args.direction.is_some() {
   970→                    return Err("direction must be absent when state is not bridled".to_string());
   971→                }
   972→                None
   973→            }
   974→            // State inherited and was bridled: inherit direction
   975→            (None, jjrg_PaceState::Bridled) => {
   976→                args.direction.or_else(|| current_tack.direction.clone())
   977→            }
   978→            // State inherited and was not bridled: no direction
   979→            (None, _) => None,
   980→        };
   981→
   982→        // Determine new text
   983→        let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
   984→        if new_text.is_empty() {
   985→            return Err("text must not be empty".to_string());
   986→        }
   987→
   988→        // Determine new silks
   989→        let new_silks = args.silks.unwrap_or_else(|| current_tack.silks.clone());
   990→
   991→        // Create new Tack
   992→        let new_tack = jjrg_make_tack(
   993→            new_state,
   994→            new_text,
   995→            new_silks,
   996→            new_direction,
   997→        );
   998→
   999→        // Prepend to tacks array
  1000→        pace.tacks.insert(0, new_tack);
  1001→
  1002→        Ok(())
  1003→    }
