  1005→    /// Draft - move a Pace from one Heat to another
  1006→    ///
  1007→    /// Moves the pace to the destination heat with a new Coronet.
  1008→    /// All Tack history is preserved, with a new Tack recording the draft.
  1009→    /// State is NOT changed - draft is a move operation, not a state transition.
  1010→    pub fn jjrg_draft(&mut self, args: jjrg_DraftArgs) -> Result<jjrg_DraftResult, String> {
  1011→        // Validate positioning mutual exclusivity
  1012→        let position_count = [args.before.is_some(), args.after.is_some(), args.first]
  1013→            .iter()
  1014→            .filter(|&&x| x)
  1015→            .count();
  1016→        if position_count > 1 {
  1017→            return Err("Only one of --before, --after, or --first may be specified".to_string());
  1018→        }
  1019→
  1020→        // Parse and normalize source coronet
  1021→        let source_coronet = Coronet::jjrf_parse(&args.coronet)
  1022→            .map_err(|e| format!("Invalid coronet: {}", e))?;
  1023→        let source_coronet_key = source_coronet.jjrf_display();
  1024→
  1025→        // Extract source Firemark from coronet
  1026→        let source_firemark = source_coronet.jjrf_parent_firemark();
  1027→        let source_firemark_key = source_firemark.jjrf_display();
  1028→
  1029→        // Parse and normalize destination firemark
  1030→        let dest_firemark = Firemark::jjrf_parse(&args.to)
  1031→            .map_err(|e| format!("Invalid destination firemark: {}", e))?;
  1032→        let dest_firemark_key = dest_firemark.jjrf_display();
  1033→
  1034→        // Validate source and destination are different
  1035→        if source_firemark_key == dest_firemark_key {
  1036→            return Err("Cannot draft pace to same heat".to_string());
  1037→        }
  1038→
  1039→        // Verify source heat exists
  1040→        if !self.heats.contains_key(&source_firemark_key) {
  1041→            return Err(format!("Source heat '{}' not found", source_firemark_key));
  1042→        }
  1043→
  1044→        // Verify destination heat exists
  1045→        if !self.heats.contains_key(&dest_firemark_key) {
  1046→            return Err(format!("Heat '{}' not found", dest_firemark_key));
  1047→        }
  1048→
  1049→        // Verify pace exists in source heat
  1050→        {
  1051→            let source_heat = self.heats.get(&source_firemark_key).unwrap();
  1052→            if !source_heat.paces.contains_key(&source_coronet_key) {
  1053→                return Err(format!("Pace {} not found in heat {}", source_coronet_key, source_firemark_key));
  1054→            }
  1055→        }
  1056→
  1057→        // Validate positioning target if specified
  1058→        let insert_position = if let Some(ref before_str) = args.before {
  1059→            let target = Coronet::jjrf_parse(before_str)
  1060→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
  1061→            let target_key = target.jjrf_display();
  1062→            let dest_heat = self.heats.get(&dest_firemark_key).unwrap();
  1063→            let pos = dest_heat.order.iter().position(|c| c == &target_key)
  1064→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
  1065→            Some(pos)
  1066→        } else if let Some(ref after_str) = args.after {
  1067→            let target = Coronet::jjrf_parse(after_str)
  1068→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
  1069→            let target_key = target.jjrf_display();
  1070→            let dest_heat = self.heats.get(&dest_firemark_key).unwrap();
  1071→            let pos = dest_heat.order.iter().position(|c| c == &target_key)
  1072→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, dest_firemark_key))?;
  1073→            Some(pos + 1)
  1074→        } else if args.first {
  1075→            Some(0)
  1076→        } else {
  1077→            None // Append to end
  1078→        };
  1079→
  1080→        // Remove pace from source heat
  1081→        let source_heat = self.heats.get_mut(&source_firemark_key).unwrap();
  1082→        let pace_data = source_heat.paces.remove(&source_coronet_key)
  1083→            .ok_or_else(|| format!("Pace {} not found", source_coronet_key))?;
  1084→        source_heat.order.retain(|c| c != &source_coronet_key);
  1085→
  1086→        // Get destination heat and allocate new coronet
  1087→        let dest_heat = self.heats.get_mut(&dest_firemark_key).unwrap();
  1088→        let new_coronet_str = format!("{}{}{}", CORONET_PREFIX, dest_firemark.jjrf_as_str(), dest_heat.next_pace_seed);
  1089→
  1090→        // Create new tack recording the draft
  1091→        let first_tack = pace_data.tacks.first();
  1092→        let draft_note = format!("Drafted from {} in {}.\n\n{}",
  1093→            source_coronet_key, source_firemark_key,
  1094→            first_tack.map(|t| t.text.as_str()).unwrap_or(""));
  1095→
  1096→        let draft_tack = jjrg_make_tack(
  1097→            first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough),
  1098→            draft_note,
  1099→            first_tack.map(|t| t.silks.clone()).unwrap_or_default(),
  1100→            first_tack.and_then(|t| t.direction.clone()),
  1101→        );
  1102→
  1103→        // Build new pace with draft tack prepended
  1104→        let mut new_tacks = vec![draft_tack];
  1105→        new_tacks.extend(pace_data.tacks);
  1106→
  1107→        let new_pace = jjrg_Pace {
  1108→            tacks: new_tacks,
  1109→        };
  1110→
  1111→        // Insert into destination heat
  1112→        match insert_position {
  1113→            Some(pos) => dest_heat.order.insert(pos, new_coronet_str.clone()),
  1114→            None => dest_heat.order.push(new_coronet_str.clone()),
  1115→        }
  1116→        dest_heat.paces.insert(new_coronet_str.clone(), new_pace);
  1117→
  1118→        // Increment destination seed
  1119→        dest_heat.next_pace_seed = zjjrg_increment_seed(&dest_heat.next_pace_seed);
  1120→
  1121→        Ok(jjrg_DraftResult { new_coronet: new_coronet_str })
  1122→    }
  1123→
  1124→    /// Retire a Heat
  1125→    ///
  1126→    /// Creates trophy file, removes heat from gallops, deletes paddock file.
  1127→    /// Does NOT save gallops or commit - caller is responsible for that.
  1128→    pub fn jjrg_retire(
  1129→        &mut self,
  1130→        args: jjrg_RetireArgs,
  1131→        base_path: &Path,
  1132→        steeplechase: &[SteeplechaseEntry],
  1133→    ) -> Result<jjrg_RetireResult, String> {
  1134→        // Parse and normalize firemark
  1135→        let firemark = Firemark::jjrf_parse(&args.firemark)
  1136→            .map_err(|e| format!("Invalid firemark: {}", e))?;
  1137→        let firemark_key = firemark.jjrf_display();
  1138→
  1139→        // Validate today is YYMMDD
  1140→        if !zjjrg_is_yymmdd(&args.today) {
  1141→            return Err(format!("today must be YYMMDD format, got '{}'", args.today));
  1142→        }
  1143→
  1144→        // Verify heat exists
  1145→        let heat = self.heats.get(&firemark_key)
  1146→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
  1147→
  1148→        // Read paddock content before we remove anything
  1149→        let paddock_path = base_path.join(&heat.paddock_file);
  1150→        let paddock_content = fs::read_to_string(&paddock_path)
  1151→            .map_err(|e| format!("Failed to read paddock file '{}': {}", heat.paddock_file, e))?;
  1152→
  1153→        // Build trophy content
  1154→        let trophy_content = self.zjjrg_build_trophy_content(&firemark_key, heat, &paddock_content, &args.today, steeplechase)?;
  1155→
  1156→        // Compute trophy path: .claude/jjm/retired/jjh_<created>-r<today>-<silks>.md
  1157→        let trophy_filename = format!(
  1158→            "jjh_{}-r{}-{}.md",
  1159→            heat.creation_time,
  1160→            args.today,
  1161→            heat.silks
  1162→        );
  1163→        let trophy_rel_path = format!(".claude/jjm/retired/{}", trophy_filename);
  1164→        let trophy_full_path = base_path.join(&trophy_rel_path);
  1165→
  1166→        // Create retired directory if needed
  1167→        if let Some(parent) = trophy_full_path.parent() {
  1168→            fs::create_dir_all(parent)
  1169→                .map_err(|e| format!("Failed to create retired directory: {}", e))?;
  1170→        }
  1171→
  1172→        // Write trophy file
  1173→        fs::write(&trophy_full_path, trophy_content)
  1174→            .map_err(|e| format!("Failed to write trophy file: {}", e))?;
  1175→
  1176→        // Capture info for result before removing heat
  1177→        let silks = heat.silks.clone();
  1178→        let paddock_file = heat.paddock_file.clone();
  1179→
  1180→        // Remove heat from gallops (do NOT change next_heat_seed)
  1181→        self.heats.remove(&firemark_key);
  1182→
  1183→        // Delete paddock file
  1184→        if paddock_path.exists() {
  1185→            fs::remove_file(&paddock_path)
  1186→                .map_err(|e| format!("Failed to delete paddock file: {}", e))?;
  1187→        }
  1188→
  1189→        Ok(jjrg_RetireResult {
  1190→            trophy_path: trophy_rel_path,
  1191→            paddock_path: paddock_file,
  1192→            silks,
  1193→            firemark: firemark_key,
  1194→        })
  1195→    }
