  1219→    /// Build trophy markdown content
  1220→    fn zjjrg_build_trophy_content(
  1221→        &self,
  1222→        firemark_key: &str,
  1223→        heat: &jjrg_Heat,
  1224→        paddock_content: &str,
  1225→        today: &str,
  1226→        steeplechase: &[SteeplechaseEntry],
  1227→    ) -> Result<String, String> {
  1228→        let mut content = String::new();
  1229→
  1230→        // Header
  1231→        content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
  1232→        content.push_str(&format!("**Firemark:** {}\n", firemark_key));
  1233→        content.push_str(&format!("**Created:** {}\n", heat.creation_time));
  1234→        content.push_str(&format!("**Retired:** {}\n", today));
  1235→        content.push_str("**Status:** retired\n\n");
  1236→
  1237→        // Paddock
  1238→        content.push_str("## Paddock\n\n");
  1239→        content.push_str(paddock_content);
  1240→        if !paddock_content.ends_with('\n') {
  1241→            content.push('\n');
  1242→        }
  1243→        content.push('\n');
  1244→
  1245→        // Paces (in order)
  1246→        content.push_str("## Paces\n\n");
  1247→        for coronet_key in &heat.order {
  1248→            if let Some(pace) = heat.paces.get(coronet_key) {
  1249→                // Get final state from most recent tack
  1250→                let final_state = pace.tacks.first()
  1251→                    .map(|t| match t.state {
  1252→                        jjrg_PaceState::Rough => "rough",
  1253→                        jjrg_PaceState::Bridled => "bridled",
  1254→                        jjrg_PaceState::Complete => "complete",
  1255→                        jjrg_PaceState::Abandoned => "abandoned",
  1256→                    })
  1257→                    .unwrap_or("unknown");
  1258→
  1259→                let pace_silks = pace.tacks.first()
  1260→                    .map(|t| t.silks.as_str())
  1261→                    .unwrap_or("unknown");
  1262→
  1263→                content.push_str(&format!(
  1264→                    "### {} ({}) [{}]\n\n",
  1265→                    pace_silks, coronet_key, final_state
  1266→                ));
  1267→
  1268→                // Tack history (newest first, as stored)
  1269→                for tack in &pace.tacks {
  1270→                    let state_str = match tack.state {
  1271→                        jjrg_PaceState::Rough => "rough",
  1272→                        jjrg_PaceState::Bridled => "bridled",
  1273→                        jjrg_PaceState::Complete => "complete",
  1274→                        jjrg_PaceState::Abandoned => "abandoned",
  1275→                    };
  1276→                    content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
  1277→                    content.push_str(&tack.text);
  1278→                    if !tack.text.ends_with('\n') {
  1279→                        content.push('\n');
  1280→                    }
  1281→                    if let Some(ref direction) = tack.direction {
  1282→                        content.push_str(&format!("\n*Direction:* {}\n", direction));
  1283→                    }
  1284→                    content.push('\n');
  1285→                }
  1286→            }
  1287→        }
  1288→
  1289→        // Steeplechase (newest first, as provided)
  1290→        content.push_str("## Steeplechase\n\n");
  1291→        if steeplechase.is_empty() {
  1292→            content.push_str("(no entries)\n\n");
  1293→        } else {
  1294→            for entry in steeplechase {
  1295→                // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
  1296→                let identity = entry.coronet.as_deref().unwrap_or("Heat");
  1297→                let action = entry.action.as_deref().unwrap_or("notch");
  1298→                content.push_str(&format!(
  1299→                    "### {} - {} - {}\n\n",
  1300→                    entry.timestamp, identity, action
  1301→                ));
  1302→                content.push_str(&entry.subject);
  1303→                if !entry.subject.ends_with('\n') {
  1304→                    content.push('\n');
  1305→                }
  1306→                content.push('\n');
  1307→            }
  1308→        }
  1309→
  1310→        Ok(content)
  1311→    }
