  1313→    /// Furlough a Heat - change status or rename
  1314→    ///
  1315→    /// Updates heat status (racing/stabled) and/or silks.
  1316→    /// At least one change must be requested.
  1317→    pub fn jjrg_furlough(&mut self, args: jjrg_FurloughArgs) -> Result<(), String> {
  1318→        // Validate at least one option provided
  1319→        if !args.racing && !args.stabled && args.silks.is_none() {
  1320→            return Err("At least one option required: --racing, --stabled, or --silks".to_string());
  1321→        }
  1322→
  1323→        // Validate racing/stabled mutual exclusivity
  1324→        if args.racing && args.stabled {
  1325→            return Err("Cannot specify both --racing and --stabled".to_string());
  1326→        }
  1327→
  1328→        // Validate silks if provided
  1329→        if let Some(ref silks) = args.silks {
  1330→            if !zjjrg_is_kebab_case(silks) {
  1331→                return Err(format!("silks must be kebab-case, got '{}'", silks));
  1332→            }
  1333→        }
  1334→
  1335→        // Parse and normalize firemark
  1336→        let firemark = Firemark::jjrf_parse(&args.firemark)
  1337→            .map_err(|e| format!("Invalid firemark: {}", e))?;
  1338→        let firemark_key = firemark.jjrf_display();
  1339→
  1340→        // Verify Heat exists
  1341→        let heat = self.heats.get_mut(&firemark_key)
  1342→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
  1343→
  1344→        // Check not retired (terminal state)
  1345→        if heat.status == jjrg_HeatStatus::Retired {
  1346→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
  1347→        }
  1348→
  1349→        // Apply status change if requested
  1350→        if args.racing {
  1351→            if heat.status == jjrg_HeatStatus::Racing {
  1352→                return Err(format!("Heat '{}' is already racing", firemark_key));
  1353→            }
  1354→            heat.status = jjrg_HeatStatus::Racing;
  1355→        } else if args.stabled {
  1356→            if heat.status == jjrg_HeatStatus::Stabled {
  1357→                return Err(format!("Heat '{}' is already stabled", firemark_key));
  1358→            }
  1359→            heat.status = jjrg_HeatStatus::Stabled;
  1360→        }
  1361→
  1362→        // Apply silks change if requested
  1363→        if let Some(silks) = args.silks {
  1364→            heat.silks = silks;
  1365→        }
  1366→
  1367→        Ok(())
  1368→    }
  1369→}
